import{_ as s,o as e,c as a,a2 as t}from"./chunks/framework.BRk9mohw.js";const r=JSON.parse('{"title":"后台执行 + 进程工具","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gateway/background-process.md","filePath":"tools/gateway/background-process.md"}'),l={name:"tools/gateway/background-process.md"};function o(d,i,h,n,p,c){return e(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="后台执行-进程工具" tabindex="-1">后台执行 + 进程工具 <a class="header-anchor" href="#后台执行-进程工具" aria-label="Permalink to &quot;后台执行 + 进程工具&quot;">​</a></h1><p>OpenClaw 通过 <code>exec</code> 工具运行 shell 命令，并将长期运行的任务保留在内存中。<code>process</code> 工具管理这些后台会话。</p><h2 id="exec-工具" tabindex="-1">exec 工具 <a class="header-anchor" href="#exec-工具" aria-label="Permalink to &quot;exec 工具&quot;">​</a></h2><p>关键参数：</p><ul><li><code>command</code>（必需）</li><li><code>yieldMs</code>（默认 10000）：此延迟后自动后台</li><li><code>background</code>（布尔值）：立即后台</li><li><code>timeout</code>（秒，默认 1800）：此超时后终止进程</li><li><code>elevated</code>（布尔值）：如果启用/允许提升模式则在主机上运行</li><li>需要真正的 TTY？设置 <code>pty: true</code>。</li><li><code>workdir</code>、<code>env</code></li></ul><p>行为：</p><ul><li>前台运行直接返回输出。</li><li>后台时（显式或超时），工具返回 <code>status: &quot;running&quot;</code> + <code>sessionId</code> 和一小段尾部。</li><li>输出保留在内存中，直到会话被轮询或清除。</li><li>如果 <code>process</code> 工具被禁止，<code>exec</code> 同步运行并忽略 <code>yieldMs</code>/<code>background</code>。</li><li>生成的后台 exec 命令接收 <code>OPENCLAW_SHELL=exec</code> 以进行上下文感知的 shell/profile 规则。</li></ul><h2 id="子进程桥接" tabindex="-1">子进程桥接 <a class="header-anchor" href="#子进程桥接" aria-label="Permalink to &quot;子进程桥接&quot;">​</a></h2><p>当在 exec/process 工具外部生成长期运行的子进程时（例如 CLI 重生或网关辅助工具），附加子进程桥接助手，以便终止信号被转发，退出/错误时监听器被分离。这避免了 systemd 上的孤立进程，并保持跨平台的关闭行为一致。</p><p>环境变量覆盖：</p><ul><li><code>PI_BASH_YIELD_MS</code>：默认 yield（毫秒）</li><li><code>PI_BASH_MAX_OUTPUT_CHARS</code>：内存输出上限（字符）</li><li><code>OPENCLAW_BASH_PENDING_MAX_OUTPUT_CHARS</code>：每个流的待处理 stdout/stderr 上限（字符）</li><li><code>PI_BASH_JOB_TTL_MS</code>：已完成会话的 TTL（毫秒，限制为 1 分钟-3 小时）</li></ul><p>配置（首选）：</p><ul><li><code>tools.exec.backgroundMs</code>（默认 10000）</li><li><code>tools.exec.timeoutSec</code>（默认 1800）</li><li><code>tools.exec.cleanupMs</code>（默认 1800000）</li><li><code>tools.exec.notifyOnExit</code>（默认 true）：当后台 exec 退出时加入系统事件 + 请求心跳</li><li><code>tools.exec.notifyOnExitEmptySuccess</code>（默认 false）：为 true 时，也为产生无输出的成功后台运行加入完成事件</li></ul><h2 id="process-工具" tabindex="-1">process 工具 <a class="header-anchor" href="#process-工具" aria-label="Permalink to &quot;process 工具&quot;">​</a></h2><p>操作：</p><ul><li><code>list</code>：运行 + 已完成的会话</li><li><code>poll</code>：排干会话的新输出（也报告退出状态）</li><li><code>log</code>：读取聚合输出（支持 <code>offset</code> + <code>limit</code>）</li><li><code>write</code>：发送 stdin（<code>data</code>，可选 <code>eof</code>）</li><li><code>kill</code>：终止后台会话</li><li><code>clear</code>：从内存中移除已完成的会话</li><li><code>remove</code>：如果正在运行则杀死，否则清除（如果已完成）</li></ul><p>注意：</p><ul><li>只有后台会话才会被列出/持久化在内存中。</li><li>进程重启后会话会丢失（无磁盘持久化）。</li><li>仅当你运行 <code>process poll/log</code> 并记录工具结果时，会话日志才会保存到聊天历史。</li><li><code>process</code> 按代理范围；它只能看到该代理启动的会话。</li><li><code>process list</code> 包含派生的 <code>name</code>（命令动词 + 目标）以供快速扫描。</li><li><code>process log</code> 使用基于行的 <code>offset</code>/<code>limit</code>。</li><li>当省略 <code>offset</code> 和 <code>limit</code> 时，它返回最后 200 行并包含分页提示。</li><li>当提供 <code>offset</code> 但省略 <code>limit</code> 时，它从 <code>offset</code> 返回到结尾（不限制为 200）。</li></ul><h2 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h2><p>运行长期任务并稍后轮询：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;exec&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sleep 5 &amp;&amp; echo done&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;yieldMs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;process&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;poll&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sessionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;id&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>立即在后台启动：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;exec&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npm run build&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;background&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><p>发送 stdin：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;process&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;action&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;write&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;sessionId&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;id&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;y</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div>',26)])])}const E=s(l,[["render",o]]);export{r as __pageData,E as default};
